// ─── Image Carousel ───────────────────────────────────────────────────────────
function ImageCarousel({ images }) {
    const [idx, setIdx] = useState(0);
    if (!images || images.length === 0) return null;
    return (
        <div style={{ position: "relative", borderRadius: 10, overflow: "hidden" }}>
            <img
                src={images[idx]}
                alt={`post-${idx}`}
                style={{ width: "100%", height: 260, objectFit: "cover", display: "block" }}
            />
            {images.length > 1 && (
                <>
                    <button
                        onClick={() => setIdx((i) => (i - 1 + images.length) % images.length)}
                        style={{
                            position: "absolute", left: 8, top: "50%", transform: "translateY(-50%)",
                            background: "rgba(0,0,0,0.45)", border: "none", borderRadius: "50%",
                            width: 30, height: 30, display: "flex", alignItems: "center",
                            justifyContent: "center", cursor: "pointer", color: "#fff",
                        }}
                    ><ChevronLeft size={16} /></button>
                    <button
                        onClick={() => setIdx((i) => (i + 1) % images.length)}
                        style={{
                            position: "absolute", right: 8, top: "50%", transform: "translateY(-50%)",
                            background: "rgba(0,0,0,0.45)", border: "none", borderRadius: "50%",
                            width: 30, height: 30, display: "flex", alignItems: "center",
                            justifyContent: "center", cursor: "pointer", color: "#fff",
                        }}
                    ><ChevronRight size={16} /></button>
                    <div style={{ position: "absolute", bottom: 8, left: 0, right: 0, display: "flex", justifyContent: "center", gap: 5 }}>
                        {images.map((_, i) => (
                            <span
                                key={i}
                                onClick={() => setIdx(i)}
                                style={{
                                    width: 7, height: 7, borderRadius: "50%", cursor: "pointer",
                                    background: i === idx ? "#fff" : "rgba(255,255,255,0.45)",
                                    display: "inline-block",
                                }}
                            />
                        ))}
                    </div>
                </>
            )}
        </div>
    );
}
export default function CreatePostModal({ onClose, onSubmit, currentUser }) {
    console.log(currentUser)
    const [postType, setPostType] = useState("both");
    const [content, setContent] = useState("");
    const [selectedFiles, setSelectedFiles] = useState([]);
    const [submitting, setSubmitting] = useState(false);
    const [error, setError] = useState("");
    const fileInputRef = useRef();
    const api_social_url = API_BASE_URL + "api/user/socialpost/";
    const handleFileChange = (e) => {
        const files = Array.from(e.target.files);
        const newFiles = files.map((file) => ({ file, preview: URL.createObjectURL(file) }));
        setSelectedFiles((prev) => [...prev, ...newFiles].slice(0, 10));
        e.target.value = "";
    };

    const removeFile = (i) => {
        setSelectedFiles((prev) => {
            URL.revokeObjectURL(prev[i].preview);
            return prev.filter((_, j) => j !== i);
        });
    };

    const handleSubmit = async () => {
        const hasText = content.trim().length > 0;
        const hasImages = selectedFiles.length > 0;
        if (!hasText && !hasImages) {
            setError("Please add text or at least one image.");
            return;
        }
        if (content.length > 1500) {
            setError("Text must be under 1500 characters.");
            return;
        }
        setError(""); setSubmitting(true);
        try {
            const formData = new FormData();
            formData.append("content", content);
            formData.append("post_type", postType);
            formData.append("author_id", currentUser?.id || 1);
            formData.append("author_type", currentUser?.type || "investor");
            formData.append("visibility", "network");
            selectedFiles.forEach((f) => formData.append("images", f.file));

            const res = await axios.post(api_social_url + "create", formData, {
                headers: { "Content-Type": "multipart/form-data" },
            });
            if (res.data.success) {
                onSubmit(res.data.post);
                onClose();
            } else {
                setError(res.data.message || "Failed to create post.");
            }
        } catch {
            setError("Something went wrong. Please try again.");
        } finally {
            setSubmitting(false);
        }
    };

    useEffect(() => () => selectedFiles.forEach((f) => URL.revokeObjectURL(f.preview)), []);

    return (
        <div
            onClick={(e) => e.target === e.currentTarget && onClose()}
            style={{
                position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)",
                zIndex: 9999, display: "flex", alignItems: "center",
                justifyContent: "center", padding: 16,
            }}
        >
            <div style={{
                background: "#fff", borderRadius: 16, width: "100%", maxWidth: 540,
                maxHeight: "90vh", overflowY: "auto",
                boxShadow: "0 20px 60px rgba(0,0,0,0.2)",
            }}>
                {/* Modal header */}
                <div style={{
                    display: "flex", alignItems: "center", justifyContent: "space-between",
                    padding: "18px 20px", borderBottom: "1px solid #f0f0f0",
                }}>
                    <h5 style={{ margin: 0, fontSize: "1rem", fontWeight: 600 }}>Create Post</h5>
                    <button onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer", color: "#888" }}>
                        <X size={20} />
                    </button>
                </div>

                <div style={{ padding: 20 }}>
                    {/* Post type tabs */}
                    <div style={{ display: "flex", gap: 8, marginBottom: 16 }}>
                        {[
                            { key: "text", label: "Text only", icon: <Type size={13} /> },
                            { key: "image", label: "Images only", icon: <Image size={13} /> },
                            { key: "both", label: "Text + Images", icon: <span style={{ fontSize: 13 }}>📝</span> },
                        ].map(({ key, label, icon }) => (
                            <button
                                key={key}
                                onClick={() => setPostType(key)}
                                style={{
                                    flex: 1, padding: "7px 6px", borderRadius: 8, fontSize: "0.72rem",
                                    border: postType === key ? "2px solid #ff3e43" : "1.5px solid #e0e0e0",
                                    background: postType === key ? "#fff5f5" : "#fafafa",
                                    color: postType === key ? "#ff3e43" : "#555",
                                    cursor: "pointer", fontWeight: postType === key ? 600 : 400,
                                    display: "flex", alignItems: "center", justifyContent: "center", gap: 4,
                                    transition: "all 0.15s",
                                }}
                            >
                                {icon} {label}
                            </button>
                        ))}
                    </div>

                    {/* Text area */}
                    {(postType === "text" || postType === "both") && (
                        <>
                            <textarea
                                rows={4}
                                placeholder="What's on your mind? Share insights, updates, or opportunities..."
                                value={content}
                                onChange={(e) => setContent(e.target.value)}
                                style={{
                                    width: "100%", padding: "12px 14px", borderRadius: 10,
                                    border: "1.5px solid #e8e8e8", resize: "none", outline: "none",
                                    fontSize: "0.85rem", lineHeight: 1.6, boxSizing: "border-box",
                                    fontFamily: "inherit", marginBottom: 4,
                                }}
                                onFocus={(e) => (e.target.style.borderColor = "#ff3e43")}
                                onBlur={(e) => (e.target.style.borderColor = "#e8e8e8")}
                            />
                            <div style={{ textAlign: "right", fontSize: "0.7rem", color: content.length > 1400 ? "#ff3e43" : "#bbb", marginBottom: 12 }}>
                                {content.length}/1500
                            </div>
                        </>
                    )}

                    {/* Image upload */}
                    {(postType === "image" || postType === "both") && (
                        <div style={{ marginBottom: 14 }}>
                            {selectedFiles.length > 0 && (
                                <div style={{
                                    display: "grid",
                                    gridTemplateColumns: selectedFiles.length === 1 ? "1fr" : selectedFiles.length === 2 ? "1fr 1fr" : "repeat(3, 1fr)",
                                    gap: 8, marginBottom: 10,
                                }}>
                                    {selectedFiles.map((f, i) => (
                                        <div key={i} style={{ position: "relative", borderRadius: 8, overflow: "hidden", aspectRatio: "1" }}>
                                            <img src={f.preview} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
                                            <button
                                                onClick={() => removeFile(i)}
                                                style={{
                                                    position: "absolute", top: 4, right: 4,
                                                    background: "rgba(0,0,0,0.6)", border: "none", borderRadius: "50%",
                                                    width: 22, height: 22, display: "flex", alignItems: "center",
                                                    justifyContent: "center", cursor: "pointer", color: "#fff",
                                                }}
                                            ><X size={11} /></button>
                                        </div>
                                    ))}
                                </div>
                            )}
                            {selectedFiles.length < 10 && (
                                <button
                                    onClick={() => fileInputRef.current?.click()}
                                    style={{
                                        width: "100%", padding: 12, borderRadius: 10,
                                        border: "1.5px dashed #e0e0e0", background: "#fafafa",
                                        cursor: "pointer", color: "#888", fontSize: "0.82rem",
                                        display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
                                    }}
                                    onMouseOver={(e) => (e.currentTarget.style.borderColor = "#ff3e43")}
                                    onMouseOut={(e) => (e.currentTarget.style.borderColor = "#e0e0e0")}
                                >
                                    <Image size={16} />
                                    {selectedFiles.length === 0
                                        ? "Add Images (up to 10)"
                                        : `Add more (${10 - selectedFiles.length} left)`}
                                </button>
                            )}
                            <input
                                ref={fileInputRef} type="file" accept="image/*" multiple
                                style={{ display: "none" }} onChange={handleFileChange}
                            />
                        </div>
                    )}

                    {/* Error */}
                    {error && (
                        <div style={{
                            background: "#fff5f5", border: "1px solid #ffd0d0", borderRadius: 8,
                            padding: "8px 12px", marginBottom: 12, fontSize: "0.8rem", color: "#cc3333",
                        }}>
                            {error}
                        </div>
                    )}

                    {/* Visibility note */}
                    <div style={{
                        background: "#f8f9fa", borderRadius: 8, padding: "8px 12px",
                        fontSize: "0.72rem", color: "#777", marginBottom: 16,
                        display: "flex", alignItems: "flex-start", gap: 6,
                    }}>
                        <span>🌐</span>
                        <span>Visible to your shared cap table members and the Capavate Angel Group network.</span>
                    </div>

                    {/* Submit button */}
                    <button
                        onClick={handleSubmit}
                        disabled={submitting}
                        style={{
                            width: "100%", padding: 12, borderRadius: 10, border: "none",
                            background: submitting ? "#ccc" : "#ff3e43", color: "#fff",
                            fontSize: "0.88rem", fontWeight: 600,
                            cursor: submitting ? "not-allowed" : "pointer",
                            transition: "background 0.2s",
                        }}
                    >
                        {submitting ? "Posting..." : "Post Now"}
                    </button>
                </div>
            </div>
        </div>
    );
}