// ChatMessageAllModal.jsx - Full Inbox + Online Status + Unread Count + Read on Scroll
import React, { useState, useEffect, useRef, useCallback } from "react";
import { X, Send, Check, CheckCheck, Search, ArrowLeft, Smile } from "lucide-react";
import EmojiPicker from "emoji-picker-react";
import {
    getMessages,
    sendMessage,
    getUserConversations,
    initSocket,
    joinConversation,
    leaveConversation,
    onNewMessage,
    emitTypingStart,
    emitTypingEnd,
    onUserTyping,
    emitMarkAsRead,
    onMessagesRead,
    removeAllListeners,
    emitUserOnline,
    onUserStatusChange,
    emitCheckOnline,
    onOnlineStatus,
} from "../../../api/chatApi";
import axios from "axios";
import { API_BASE_URL } from "../../../config/config";

const PAGE_SIZE = 30;

export default function ChatMessageAllModal({ onClose, currentUser }) {
    const [conversations, setConversations] = useState([]);
    const [convLoading, setConvLoading] = useState(false);
    const [searchQuery, setSearchQuery] = useState("");
    const [onlineUsers, setOnlineUsers] = useState(new Set()); // "id_type" keys

    const [activeConv, setActiveConv] = useState(null);
    const [selectedUser, setSelectedUser] = useState(null);
    const [messages, setMessages] = useState([]);
    const [messageInput, setMessageInput] = useState("");
    const [loading, setLoading] = useState(false);
    const [loadingMore, setLoadingMore] = useState(false);
    const [hasMore, setHasMore] = useState(true);
    const [offset, setOffset] = useState(0);
    const [otherUserTyping, setOtherUserTyping] = useState(false);
    const [showEmojiPicker, setShowEmojiPicker] = useState(false);
    const emojiPickerRef = useRef(null);
    const [newMsgCount, setNewMsgCount] = useState(0);
    const [isAtBottom, setIsAtBottom] = useState(true);
    const isAtBottomRef = useRef(true); // ref for use inside callbacks

    const messagesEndRef = useRef(null);
    const messagesAreaRef = useRef(null);
    const typingTimeoutRef = useRef(null);
    const conversationRef = useRef(null);
    const observerRef = useRef(null);
    const topSentinelRef = useRef(null);
    const API_URL = `${API_BASE_URL}api/user/chatmessage`;
    // Get login data from localStorage (supports both types)
    const getStoredUserData = () => {
        // Try Signatory first
        let signatoryData = localStorage.getItem("SignatoryLoginData");
        if (signatoryData) {
            const userData = JSON.parse(signatoryData);
            return {
                userData: userData,
                loginType: 'signatory',
                access_token: userData?.access_token || userData?.token
            };
        }



        // Try generic InvestorData
        let investorData = localStorage.getItem("InvestorData");
        if (investorData) {
            const userData = JSON.parse(investorData);
            return {
                userData: userData,
                loginType: 'investor',
                access_token: userData?.access_token || userData?.token
            };
        }

        return null;
    };

    // Use it
    const userInfo = getStoredUserData();
    const access_token = userInfo?.access_token;

    // ── Init ────────────────────────────────────────────────────────────────
    useEffect(() => {
        if (!currentUser?.id) return;
        initSocket();

        // Announce self as online
        emitUserOnline(currentUser.id, currentUser.type, currentUser.name);

        loadConversations();

        // ✅ GLOBAL listener — saari conversations ke liye unread count update
        // Ye hamesha active rehta hai chahe koi conversation open ho ya na ho
        onNewMessage((newMsg) => {
            newMsg.sender_id = Number(newMsg.sender_id);
            newMsg.receiver_id = Number(newMsg.receiver_id);

            const isMe = newMsg.sender_id === currentUser.id;
            if (isMe) return; // apna bheja hua message ignore

            // Left panel mein last message + unread count update
            setConversations(prev => prev.map(c => {
                if (c.conversation_id !== newMsg.conversation_id) return c;

                const isP1 = c.participant1_type === currentUser.type && Number(c.participant1_id) === currentUser.id;
                const unreadKey = isP1 ? "participant1_unread" : "participant2_unread";

                // Active conversation open hai toh count increment mat karo
                const isActiveConv = conversationRef.current === newMsg.conversation_id;

                return {
                    ...c,
                    last_message: newMsg.message,
                    last_message_time: newMsg.created_at,
                    [unreadKey]: isActiveConv ? c[unreadKey] : (c[unreadKey] || 0) + 1,
                };
            }));
        });

        // Listen for online/offline status changes
        onUserStatusChange((data) => {
            const key = `${data.user_id}_${data.user_type}`;
            setOnlineUsers(prev => {
                const next = new Set(prev);
                if (data.status === "online") next.add(key);
                else next.delete(key);
                return next;
            });
        });

        onOnlineStatus((data) => {
            const key = `${data.user_id}_${data.user_type}`;
            setOnlineUsers(prev => {
                const next = new Set(prev);
                if (data.status === "online") next.add(key);
                else next.delete(key);
                return next;
            });
        });

        return () => {
            if (conversationRef.current) leaveConversation(conversationRef.current);
            removeAllListeners(["new-message", "user-typing", "messages-read", "user-status-change", "online-status"]);
            if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
            if (observerRef.current) observerRef.current.disconnect();
        };
    }, [currentUser?.id]);

    const isUserOnline = (userId, userType) => onlineUsers.has(`${userId}_${userType}`);

    // ── Load conversations ───────────────────────────────────────────────────
    const loadConversations = async () => {
        setConvLoading(true);
        try {
            const res = await getUserConversations(currentUser.type, currentUser.id);
            if (res.success) {
                // Deduplicate by other_user — keep latest
                const seen = new Map();
                res.conversations.forEach(conv => {
                    const key = `${conv.other_user_type}_${conv.other_user_id}`;
                    const existing = seen.get(key);
                    if (!existing || new Date(conv.updated_at) > new Date(existing.updated_at)) {
                        seen.set(key, conv);
                    }
                });
                const deduplicated = Array.from(seen.values());
                setConversations(deduplicated);

                // Check online status for each other user
                deduplicated.forEach(conv => {
                    emitCheckOnline(conv.other_user_id, conv.other_user_type);
                });
            }
        } catch (err) {
            console.error("loadConversations error:", err);
        } finally {
            setConvLoading(false);
        }
    };

    // ── Open conversation ────────────────────────────────────────────────────
    const openConversation = async (conv) => {
        if (conversationRef.current) {
            leaveConversation(conversationRef.current);
            removeAllListeners(["new-message", "user-typing", "messages-read"]);
        }

        setActiveConv(conv);
        setSelectedUser(conv.other_user);
        setMessages([]);
        setOffset(0);
        setHasMore(true);
        conversationRef.current = conv.conversation_id;

        joinConversation(conv.conversation_id);
        emitMarkAsRead(conv.conversation_id, currentUser.id);

        // Clear unread immediately in UI (backend also resets via getMessages)
        setConversations(prev => prev.map(c =>
            c.conversation_id === conv.conversation_id
                ? { ...c, participant1_unread: 0, participant2_unread: 0 }
                : c
        ));

        await loadMessages(conv.conversation_id, 0, true);
        setupSocketListeners(conv.conversation_id);

        // Check online status of other user
        emitCheckOnline(conv.other_user_id, conv.other_user_type);
    };

    const goBack = () => {
        if (conversationRef.current) leaveConversation(conversationRef.current);
        removeAllListeners(["new-message", "user-typing", "messages-read"]);
        setActiveConv(null);
        setSelectedUser(null);
        setMessages([]);
        conversationRef.current = null;
        loadConversations();
    };

    // ── Socket listeners ─────────────────────────────────────────────────────
    const setupSocketListeners = (convId) => {
        // Only remove typing/read — new-message global listener handles unread count
        removeAllListeners(["user-typing", "messages-read"]);

        // Per-conversation: show incoming messages in chat UI
        onNewMessage((newMsg) => {
            newMsg.sender_id = Number(newMsg.sender_id);
            newMsg.receiver_id = Number(newMsg.receiver_id);

            const isMe = newMsg.sender_id === currentUser.id;
            if (isMe || newMsg.conversation_id !== convId) return;

            setMessages((prev) => {
                if (prev.some((m) => m.id === newMsg.id)) return prev;
                if (newMsg.receiver_id === currentUser.id) {
                    markMessageRead(newMsg.id);
                    newMsg.is_read = 1;
                }
                return [...prev, newMsg];
            });

            // If user scrolled up — show badge instead of auto-scroll
            // Use ref for immediate sync check (state is async in callbacks)
            if (isAtBottomRef.current) {
                setTimeout(() => messagesEndRef.current?.scrollIntoView({ behavior: "smooth" }), 50);
            } else {
                setNewMsgCount(c => c + 1);
            }
        });

        onMessagesRead((data) => {
            if (data.user_id !== currentUser.id) {
                setMessages(prev =>
                    prev.map(m => m.sender_id === currentUser.id ? { ...m, is_read: 1 } : m)
                );
            }
        });

        onUserTyping((data) => {
            if (data.user_id !== currentUser.id) setOtherUserTyping(data.isTyping);
        });
    };

    // ── Load messages ────────────────────────────────────────────────────────
    const loadMessages = async (convId, currentOffset = 0, isInitial = false) => {
        if (isInitial) setLoading(true);
        else setLoadingMore(true);

        try {
            const response = await getMessages(convId, currentUser.id, currentUser.type, PAGE_SIZE, currentOffset);
            if (response.success) {
                const newMsgs = response.messages;
                if (isInitial) {
                    setMessages(newMsgs);
                    setOffset(PAGE_SIZE);
                    setTimeout(() => {
                        scrollToBottom();
                        setupIntersectionObserver();
                    }, 150);
                } else {
                    const area = messagesAreaRef.current;
                    const prevScrollHeight = area?.scrollHeight || 0;
                    setMessages(prev => [...newMsgs, ...prev]);
                    setOffset(currentOffset + PAGE_SIZE);
                    requestAnimationFrame(() => {
                        if (area) area.scrollTop = area.scrollHeight - prevScrollHeight;
                    });
                }
                setHasMore(newMsgs.length >= PAGE_SIZE);
            }
        } catch (err) {
            console.error("loadMessages error:", err);
        } finally {
            setLoading(false);
            setLoadingMore(false);
        }
    };

    // ── Top sentinel pagination ──────────────────────────────────────────────
    useEffect(() => {
        if (!topSentinelRef.current || !messagesAreaRef.current || !activeConv) return;
        const topObserver = new IntersectionObserver(
            (entries) => {
                if (entries[0].isIntersecting && hasMore && !loadingMore && !loading) {
                    loadMessages(activeConv.conversation_id, offset, false);
                }
            },
            { root: messagesAreaRef.current, threshold: 0.1 }
        );
        topObserver.observe(topSentinelRef.current);
        return () => topObserver.disconnect();
    }, [hasMore, loadingMore, loading, offset, activeConv]);

    // ── Read receipt observer (scroll pe read) ───────────────────────────────
    const setupIntersectionObserver = () => {
        if (observerRef.current) observerRef.current.disconnect();
        observerRef.current = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        const msgId = parseInt(entry.target.dataset.msgid);
                        const senderId = parseInt(entry.target.dataset.senderid);
                        if (senderId !== currentUser.id) {
                            markMessageRead(msgId);
                            setMessages(prev =>
                                prev.map(m => m.id === msgId ? { ...m, is_read: 1 } : m)
                            );
                        }
                    }
                });
            },
            { threshold: 0.8, root: messagesAreaRef.current }
        );
    };

    const observeMessage = useCallback((el) => {
        if (!el || !observerRef.current) return;
        // Only observe messages that are NOT yet read (is_read=0)
        if (el.dataset.isread === "0") {
            observerRef.current.observe(el);
        }
    }, []);

    const markMessageRead = async (messageId) => {
        if (!messageId || messageId.toString().startsWith("opt_")) return;
        try {
            await axios.post(
                `${API_URL}/mark-read`,
                {
                    message_id: messageId,
                    user_id: currentUser.id,
                    user_type: currentUser.type,
                },
                {
                    headers: {
                        'Accept': 'application/json',
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${access_token}`,
                    }
                }
            );

            if (conversationRef.current) {
                emitMarkAsRead(conversationRef.current, currentUser.id);
            }
        } catch (err) {
            console.error('Error marking message as read:', err);
            if (err.response?.status === 401) {
                // Token expired
                console.error('Token expired. Please login again.');
            }
        }
    };

    // ── Send ─────────────────────────────────────────────────────────────────
    const handleSendMessage = async () => {
        if (!messageInput.trim() || !activeConv || !selectedUser) return;
        const text = messageInput;
        setMessageInput("");

        const optimisticMsg = {
            id: `opt_${Date.now()}`, _optimistic: true,
            message: text,
            sender_id: currentUser.id, sender_type: currentUser.type,
            receiver_id: selectedUser.id, receiver_type: selectedUser.type || activeConv.other_user_type,
            conversation_id: activeConv.conversation_id,
            created_at: null, is_read: 0, is_delivered: 0,
        };

        setMessages(prev => [...prev, optimisticMsg]);
        scrollToBottom();
        if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
        emitTypingEnd(activeConv.conversation_id, currentUser.id);

        setConversations(prev => prev.map(c =>
            c.conversation_id === activeConv.conversation_id
                ? { ...c, last_message: text, last_message_time: new Date() }
                : c
        ));

        try {
            const res = await sendMessage(
                activeConv.conversation_id,
                currentUser.type, currentUser.id,
                selectedUser.type || activeConv.other_user_type, selectedUser.id,
                text
            );
            if (res?.success && res?.message) {
                const realMsg = res.message;
                realMsg.sender_id = Number(realMsg.sender_id);
                realMsg.receiver_id = Number(realMsg.receiver_id);
                setMessages(prev => prev.map(m => m.id === optimisticMsg.id ? realMsg : m));
            }
        } catch (err) {
            setMessages(prev => prev.filter(m => m.id !== optimisticMsg.id));
        }
    };

    const handleInputChange = (e) => {
        setMessageInput(e.target.value);
        if (!activeConv) return;
        emitTypingStart(activeConv.conversation_id, currentUser.id, currentUser.name);
        if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
        typingTimeoutRef.current = setTimeout(() => emitTypingEnd(activeConv.conversation_id, currentUser.id), 1500);
    };

    const handleKeyPress = (e) => {
        if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSendMessage(); }
    };

    // Close emoji picker on outside click
    useEffect(() => {
        const handleClickOutside = (e) => {
            if (emojiPickerRef.current && !emojiPickerRef.current.contains(e.target)) {
                setShowEmojiPicker(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const onEmojiClick = (emojiData) => {
        setMessageInput(prev => prev + emojiData.emoji);
    };

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
        setNewMsgCount(0);
        isAtBottomRef.current = true;
        setIsAtBottom(true);
    };

    const handleScroll = () => {
        const area = messagesAreaRef.current;
        if (!area) return;
        const distFromBottom = area.scrollHeight - area.scrollTop - area.clientHeight;
        const atBottom = distFromBottom < 80;
        isAtBottomRef.current = atBottom;  // sync update for callbacks
        setIsAtBottom(atBottom);
        if (atBottom) setNewMsgCount(0);   // clear badge when scrolled to bottom
    };

    // ── Helpers ──────────────────────────────────────────────────────────────
    const parseTimestamp = (ts) => {
        if (!ts) return new Date();
        if (ts instanceof Date) return ts;
        const s = ts.toString().trim();
        if (s.includes("Z") || s.match(/[+-]\d{2}:\d{2}$/)) return new Date(s);
        return new Date(s.replace(" ", "T") + "Z");
    };

    const formatMessageTime = (timestamp) => {
        if (!timestamp) return "sending...";
        const msgDate = parseTimestamp(timestamp);
        const now = new Date();
        const diffDays = Math.round((new Date(now.getFullYear(), now.getMonth(), now.getDate()) - new Date(msgDate.getFullYear(), msgDate.getMonth(), msgDate.getDate())) / 86400000);
        const timeStr = msgDate.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", hour12: true });
        if (diffDays === 0) return timeStr;
        if (diffDays === 1) return `Yesterday ${timeStr}`;
        if (diffDays < 7) return `${msgDate.toLocaleDateString([], { weekday: "short" })} ${timeStr}`;
        return `${msgDate.toLocaleDateString([], { day: "2-digit", month: "short", year: "numeric" })} ${timeStr}`;
    };

    const formatConvTime = (timestamp) => {
        if (!timestamp) return "";
        const d = parseTimestamp(timestamp);
        const now = new Date();
        const diffDays = Math.round((new Date(now.getFullYear(), now.getMonth(), now.getDate()) - new Date(d.getFullYear(), d.getMonth(), d.getDate())) / 86400000);
        if (diffDays === 0) return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", hour12: true });
        if (diffDays === 1) return "Yesterday";
        if (diffDays < 7) return d.toLocaleDateString([], { weekday: "short" });
        return d.toLocaleDateString([], { day: "2-digit", month: "short" });
    };

    const getDateLabel = (timestamp) => {
        if (!timestamp) return "";
        const msgDate = parseTimestamp(timestamp);
        const now = new Date();
        const diffDays = Math.round((new Date(now.getFullYear(), now.getMonth(), now.getDate()) - new Date(msgDate.getFullYear(), msgDate.getMonth(), msgDate.getDate())) / 86400000);
        if (diffDays === 0) return "Today";
        if (diffDays === 1) return "Yesterday";
        if (diffDays < 7) return msgDate.toLocaleDateString([], { weekday: "long" });
        return msgDate.toLocaleDateString([], { day: "2-digit", month: "long", year: "numeric" });
    };

    const getRoleColor = (role) => {
        if (role === "company") return "#ff3e43";
        if (role === "investor") return "#22c55e";
        if (role === "admin") return "#9c27b0";
        return "#6c757d";
    };

    const getUnreadCount = (conv) => {
        if (!currentUser) return 0;
        // participant1_unread = unread count FOR participant1 (messages they haven't read)
        // participant2_unread = unread count FOR participant2
        // We show current user's OWN unread count (messages sent TO them that they haven't read)
        const amIP1 = conv.participant1_type === currentUser.type && Number(conv.participant1_id) === currentUser.id;
        const amIP2 = conv.participant2_type === currentUser.type && Number(conv.participant2_id) === currentUser.id;
        if (amIP1) return conv.participant1_unread || 0;
        if (amIP2) return conv.participant2_unread || 0;
        return 0;
    };

    const TickIcon = ({ msg }) => {
        if (msg._optimistic) return <Check size={11} color="rgba(255,255,255,0.45)" />;
        if (msg.is_read === 1) return <CheckCheck size={11} color="#4fc3f7" />;
        if (msg.is_delivered) return <CheckCheck size={11} color="rgba(255,255,255,0.55)" />;
        return <Check size={11} color="rgba(255,255,255,0.55)" />;
    };

    const filteredConvs = conversations.filter(c =>
        c.other_user?.name?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    // ── Render ───────────────────────────────────────────────────────────────
    return (
        <>
            <style>{`
                @keyframes typingBlink{0%,80%,100%{opacity:.25;transform:scale(.85)}40%{opacity:1;transform:scale(1.15)}}
                @keyframes spin{to{transform:rotate(360deg)}}
                @keyframes pulse{0%,100%{opacity:1}50%{opacity:.5}}
                .cm-typing-dot{display:inline-block;width:6px;height:6px;border-radius:50%;background:#bcc4ce;animation:typingBlink 1.4s infinite both;margin:0 2px}
                .cm-typing-dot:nth-child(2){animation-delay:.2s}
                .cm-typing-dot:nth-child(3){animation-delay:.4s}
                .cm-input:focus{border-color:#ff3e43!important;box-shadow:0 0 0 3px rgba(255,62,67,.1)!important;background:#fff!important}
                .cm-send:hover:not(:disabled){transform:scale(1.08)}
                .cm-close:hover{background:#f3f4f6!important}
                .conv-item:hover{background:#f6f7fb!important}
                .cm-body::-webkit-scrollbar,.conv-list::-webkit-scrollbar{width:3px}
                .cm-body::-webkit-scrollbar-thumb,.conv-list::-webkit-scrollbar-thumb{background:#dde1e7;border-radius:2px}
                .search-input:focus{outline:none}
                .back-btn:hover{background:#f3f4f6!important}
            `}</style>

            <div style={S.overlay}>
                <div style={S.modal}>

                    {/* ── LEFT PANEL ── */}
                    <div style={S.leftPanel}>
                        <div style={S.leftHeader}>
                            <div style={S.leftHeaderTop}>
                                <span style={S.leftTitle}>Messages</span>
                                <button className="cm-close" onClick={onClose} style={S.closeBtn}>
                                    <X size={17} color="#9ca3af" />
                                </button>
                            </div>
                            <div style={S.searchBox}>
                                <Search size={14} color="#adb5bd" style={{ flexShrink: 0 }} />
                                <input
                                    className="search-input"
                                    placeholder="Search conversations..."
                                    value={searchQuery}
                                    onChange={e => setSearchQuery(e.target.value)}
                                    style={S.searchInput}
                                />
                            </div>
                        </div>

                        <div className="conv-list" style={S.convList}>
                            {convLoading ? (
                                <div style={S.convLoading}><div style={S.smallSpinner} /></div>
                            ) : filteredConvs.length === 0 ? (
                                <div style={S.convEmpty}>
                                    <div style={{ fontSize: 28 }}>💬</div>
                                    <div style={{ fontSize: 13, color: "#9ca3af", marginTop: 6 }}>No conversations yet</div>
                                </div>
                            ) : (
                                filteredConvs.map(conv => {
                                    const unread = getUnreadCount(conv);
                                    const isActive = activeConv?.conversation_id === conv.conversation_id;
                                    const online = isUserOnline(conv.other_user_id, conv.other_user_type);
                                    return (
                                        <div
                                            key={conv.conversation_id}
                                            className="conv-item"
                                            onClick={() => openConversation(conv)}
                                            style={{ ...S.convItem, background: isActive ? "#fff5f5" : "#fff" }}
                                        >
                                            {/* Avatar with online dot */}
                                            <div style={{ position: "relative", flexShrink: 0 }}>
                                                <div style={{ ...S.convAvatar, background: `linear-gradient(135deg, ${getRoleColor(conv.other_user_type)}, ${getRoleColor(conv.other_user_type)}bb)`, overflow: "hidden", position: "relative" }}>
                                                    {conv.other_user?.avatar && conv.other_user.avatar !== "https://example.com/avatar.jpg" ? (
                                                        <img src={conv.other_user.avatar} alt={conv.other_user.name}
                                                            style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: "50%", position: "absolute", top: 0, left: 0 }}
                                                            onError={(e) => { e.target.style.display = "none"; }}
                                                        />
                                                    ) : null}
                                                    <span>{conv.other_user?.name?.charAt(0)?.toUpperCase() || "?"}</span>
                                                </div>
                                                {/* Online/Offline dot */}
                                                <span style={{
                                                    ...S.statusDot,
                                                    background: online ? "#22c55e" : "#d1d5db",
                                                }} />
                                            </div>

                                            <div style={S.convInfo}>
                                                <div style={S.convRow1}>
                                                    <span style={{ ...S.convName, fontWeight: unread > 0 ? 700 : 500 }}>
                                                        {conv.other_user?.name || "Unknown"}
                                                    </span>
                                                    <span style={S.convTime}>{formatConvTime(conv.last_message_time || conv.updated_at)}</span>
                                                </div>
                                                <div style={S.convRow2}>
                                                    <span style={{ ...S.convLastMsg, fontWeight: unread > 0 ? 600 : 400, color: unread > 0 ? "#374151" : "#9ca3af" }}>
                                                        {conv.last_message
                                                            ? conv.last_message.length > 32 ? conv.last_message.substring(0, 32) + "..." : conv.last_message
                                                            : "Start a conversation"}
                                                    </span>
                                                    {unread > 0 && (
                                                        <span style={S.unreadBadge}>{unread > 99 ? "99+" : unread}</span>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    );
                                })
                            )}
                        </div>
                    </div>

                    {/* ── RIGHT PANEL ── */}
                    <div style={S.rightPanel}>
                        {!activeConv ? (
                            <div style={S.noChatSelected}>
                                <div style={{ fontSize: 48 }}>💬</div>
                                <div style={{ fontSize: 16, fontWeight: 600, color: "#6b7280", marginTop: 12 }}>Select a conversation</div>
                                <div style={{ fontSize: 13, color: "#b0b8c4", marginTop: 4 }}>Choose from your existing conversations</div>
                            </div>
                        ) : (
                            <>
                                {/* Chat Header */}
                                <div style={S.chatHeader}>
                                    <div style={S.chatHeaderLeft}>
                                        <button className="back-btn" onClick={goBack} style={S.backBtn}>
                                            <ArrowLeft size={18} color="#6b7280" />
                                        </button>
                                        <div style={{ position: "relative" }}>
                                            <div style={{ ...S.chatAvatar, background: `linear-gradient(135deg, ${getRoleColor(activeConv.other_user_type)}, ${getRoleColor(activeConv.other_user_type)}bb)`, overflow: "hidden", position: "relative" }}>
                                                {selectedUser?.avatar && selectedUser.avatar !== "https://example.com/avatar.jpg" ? (
                                                    <img src={selectedUser.avatar} alt={selectedUser.name}
                                                        style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: "50%", position: "absolute", top: 0, left: 0 }}
                                                        onError={(e) => { e.target.style.display = "none"; }}
                                                    />
                                                ) : null}
                                                <span>{selectedUser?.name?.charAt(0)?.toUpperCase()}</span>
                                            </div>
                                            <span style={{
                                                ...S.statusDot,
                                                width: 11, height: 11,
                                                background: isUserOnline(activeConv.other_user_id, activeConv.other_user_type) ? "#22c55e" : "#d1d5db",
                                            }} />
                                        </div>
                                        <div>
                                            <div style={S.chatName}>{selectedUser?.name}</div>
                                            <div style={{ display: "flex", alignItems: "center", gap: 5 }}>
                                                <span style={{ ...S.chatBadge, background: getRoleColor(activeConv.other_user_type) }}>
                                                    {activeConv.other_user_type}
                                                </span>
                                                <span style={{
                                                    fontSize: 11,
                                                    color: isUserOnline(activeConv.other_user_id, activeConv.other_user_type) ? "#22c55e" : "#9ca3af",
                                                    fontWeight: 500,
                                                }}>
                                                    {isUserOnline(activeConv.other_user_id, activeConv.other_user_type) ? "● Online" : "○ Offline"}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                    <button className="cm-close" onClick={onClose} style={S.closeBtn}>
                                        <X size={17} color="#9ca3af" />
                                    </button>
                                </div>

                                {/* Messages */}
                                <div className="cm-body" ref={messagesAreaRef} style={S.body} onScroll={handleScroll}>
                                    <div ref={topSentinelRef} style={{ height: 1 }} />
                                    {loadingMore && <div style={S.loadMoreBox}><div style={S.loadMoreSpinner} /></div>}
                                    {!hasMore && messages.length > 0 && (
                                        <div style={S.noMoreBox}><span style={S.noMoreText}>No more messages</span></div>
                                    )}

                                    {loading ? (
                                        <div style={S.centerBox}><div style={S.spinner} /></div>
                                    ) : messages.length === 0 ? (
                                        <div style={S.centerBox}>
                                            <div style={{ fontSize: 32 }}>👋</div>
                                            <div style={{ fontSize: 13, color: "#9ca3af", marginTop: 8 }}>Say hello to {selectedUser?.name}!</div>
                                        </div>
                                    ) : (
                                        messages.map((msg, idx) => {
                                            const isMe = msg.sender_id === currentUser?.id;
                                            const prevMsg = messages[idx - 1];
                                            const showDateSep = !prevMsg || getDateLabel(msg.created_at) !== getDateLabel(prevMsg.created_at);
                                            return (
                                                <React.Fragment key={msg.id || idx}>
                                                    {showDateSep && (
                                                        <div style={S.dateSep}><span style={S.dateSepText}>{getDateLabel(msg.created_at)}</span></div>
                                                    )}
                                                    <div
                                                        ref={!isMe && msg.is_read === 0 ? observeMessage : null}
                                                        data-msgid={msg.id}
                                                        data-senderid={msg.sender_id}
                                                        data-isread={msg.is_read || 0}
                                                        style={{ ...S.row, justifyContent: isMe ? "flex-end" : "flex-start" }}
                                                    >
                                                        {!isMe && <div style={S.miniAvatar}>{selectedUser?.name?.charAt(0)?.toUpperCase()}</div>}
                                                        <div style={{ ...S.bubble, ...(isMe ? S.bubbleMe : S.bubbleThem), opacity: msg._optimistic ? 0.72 : 1 }}>
                                                            <p style={S.msgText}>{msg.message}</p>
                                                            <div style={S.msgMeta}>
                                                                <span style={{ ...S.msgTime, color: isMe ? "rgba(255,255,255,.6)" : "#b0b8c4" }}>
                                                                    {formatMessageTime(msg.created_at)}
                                                                </span>
                                                                {isMe && <span style={{ display: "flex", alignItems: "center", marginLeft: 3 }}><TickIcon msg={msg} /></span>}
                                                            </div>
                                                        </div>
                                                    </div>
                                                </React.Fragment>
                                            );
                                        })
                                    )}

                                    {otherUserTyping && (
                                        <div style={{ ...S.row, justifyContent: "flex-start" }}>
                                            <div style={S.miniAvatar}>{selectedUser?.name?.charAt(0)?.toUpperCase()}</div>
                                            <div style={{ ...S.bubble, ...S.bubbleThem, padding: "10px 14px", display: "flex", alignItems: "center" }}>
                                                <span className="cm-typing-dot" /><span className="cm-typing-dot" /><span className="cm-typing-dot" />
                                            </div>
                                        </div>
                                    )}
                                    <div ref={messagesEndRef} />
                                </div>

                                {/* ✅ New message floating badge */}
                                {newMsgCount > 0 && !isAtBottom && (
                                    <div
                                        onClick={scrollToBottom}
                                        style={S.newMsgBadge}
                                    >
                                        ↓ {newMsgCount} new message{newMsgCount > 1 ? "s" : ""}
                                    </div>
                                )}

                                {/* Footer */}
                                <div style={{ ...S.footer, position: "relative" }}>
                                    {showEmojiPicker && (
                                        <div ref={emojiPickerRef} style={{
                                            position: "absolute", bottom: "56px", left: "14px",
                                            zIndex: 9999, borderRadius: 12,
                                            boxShadow: "0 8px 32px rgba(0,0,0,0.18)",
                                        }}>
                                            <EmojiPicker
                                                onEmojiClick={onEmojiClick}
                                                skinTonesDisabled
                                                height={380}
                                                width={320}
                                                previewConfig={{ showPreview: false }}
                                                searchPlaceholder="Search emoji..."
                                            />
                                        </div>
                                    )}
                                    <button
                                        onClick={() => setShowEmojiPicker(prev => !prev)}
                                        style={{
                                            background: "none", border: "none", cursor: "pointer",
                                            padding: "6px", borderRadius: "50%", flexShrink: 0,
                                            color: showEmojiPicker ? "#ff3e43" : "#9ca3af",
                                            display: "flex", alignItems: "center", justifyContent: "center",
                                            transition: "color .15s",
                                        }}
                                    >
                                        <Smile size={20} />
                                    </button>
                                    <input
                                        className="cm-input"
                                        type="text"
                                        placeholder={`Message ${selectedUser?.name}…`}
                                        value={messageInput}
                                        onChange={handleInputChange}
                                        onKeyPress={handleKeyPress}
                                        style={S.input}
                                    />
                                    <button
                                        className="cm-send"
                                        onClick={handleSendMessage}
                                        disabled={!messageInput.trim()}
                                        style={{ ...S.sendBtn, opacity: !messageInput.trim() ? 0.4 : 1, cursor: !messageInput.trim() ? "not-allowed" : "pointer" }}
                                    >
                                        <Send size={15} color="#fff" />
                                    </button>
                                </div>
                            </>
                        )}
                    </div>
                </div>
            </div>
        </>
    );
}

const S = {
    overlay: { position: "fixed", inset: 0, background: "rgba(10,15,25,.65)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", backdropFilter: "blur(8px)", padding: 16 },
    modal: { width: "100%", maxWidth: 860, height: "min(680px,92vh)", background: "#f6f7fb", borderRadius: 22, display: "flex", overflow: "hidden", boxShadow: "0 28px 80px rgba(0,0,0,.22), 0 0 0 1px rgba(0,0,0,.06)" },
    leftPanel: { width: 300, minWidth: 260, flexShrink: 0, display: "flex", flexDirection: "column", background: "#fff", borderRight: "1px solid #f0f2f5" },
    leftHeader: { padding: "14px 14px 10px", borderBottom: "1px solid #f0f2f5" },
    leftHeaderTop: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 },
    leftTitle: { fontSize: 16, fontWeight: 700, color: "#111827" },
    searchBox: { display: "flex", alignItems: "center", gap: 8, background: "#f6f7fb", border: "1.5px solid #eef0f4", borderRadius: 10, padding: "7px 12px" },
    searchInput: { flex: 1, border: "none", background: "transparent", fontSize: 13, color: "#374151" },
    convList: { flex: 1, overflowY: "auto" },
    convLoading: { display: "flex", justifyContent: "center", padding: 30 },
    convEmpty: { display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 40 },
    convItem: { display: "flex", alignItems: "center", gap: 11, padding: "11px 14px", cursor: "pointer", borderBottom: "1px solid #f6f7fb", transition: "background .15s" },
    convAvatar: { width: 44, height: 44, borderRadius: "50%", color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 700, fontSize: 16 },
    statusDot: { position: "absolute", bottom: 1, right: 1, width: 10, height: 10, borderRadius: "50%", border: "2px solid #fff" },
    convInfo: { flex: 1, minWidth: 0 },
    convRow1: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 3 },
    convName: { fontSize: 13, color: "#111827", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" },
    convTime: { fontSize: 11, color: "#b0b8c4", flexShrink: 0, marginLeft: 4 },
    convRow2: { display: "flex", justifyContent: "space-between", alignItems: "center" },
    convLastMsg: { fontSize: 12, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", flex: 1 },
    unreadBadge: { background: "#ff3e43", color: "#fff", fontSize: 10, fontWeight: 700, borderRadius: 20, padding: "2px 7px", marginLeft: 6, flexShrink: 0 },
    smallSpinner: { width: 22, height: 22, borderRadius: "50%", border: "2px solid #eef0f4", borderTopColor: "#ff3e43", animation: "spin .75s linear infinite" },
    rightPanel: { flex: 1, display: "flex", flexDirection: "column", minWidth: 0, position: "relative" },
    noChatSelected: { flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" },
    chatHeader: { padding: "12px 16px", borderBottom: "1px solid #f0f2f5", display: "flex", justifyContent: "space-between", alignItems: "center", background: "#fff" },
    chatHeaderLeft: { display: "flex", alignItems: "center", gap: 10 },
    backBtn: { background: "none", border: "none", cursor: "pointer", width: 30, height: 30, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", transition: "background .15s" },
    chatAvatar: { width: 38, height: 38, borderRadius: "50%", color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 700, fontSize: 15 },
    chatName: { fontSize: 14, fontWeight: 650, color: "#111827" },
    chatBadge: { fontSize: 10, padding: "2px 8px", borderRadius: 20, color: "#fff", fontWeight: 500, display: "inline-block" },
    closeBtn: { background: "none", border: "none", cursor: "pointer", width: 32, height: 32, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", transition: "background .15s" },
    body: { flex: 1, overflowY: "auto", padding: "12px 14px 8px", display: "flex", flexDirection: "column", gap: 1, background: "#f6f7fb" },
    centerBox: { flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 6, padding: 40 },
    loadMoreBox: { display: "flex", justifyContent: "center", padding: "6px 0" },
    loadMoreSpinner: { width: 18, height: 18, borderRadius: "50%", border: "2px solid #eef0f4", borderTopColor: "#ff3e43", animation: "spin .75s linear infinite" },
    noMoreBox: { display: "flex", justifyContent: "center", padding: "4px 0" },
    noMoreText: { fontSize: 11, color: "#c4c9d4", background: "#eef0f4", padding: "3px 12px", borderRadius: 20 },
    spinner: { width: 24, height: 24, borderRadius: "50%", border: "3px solid #eef0f4", borderTopColor: "#ff3e43", animation: "spin .75s linear infinite" },
    dateSep: { display: "flex", alignItems: "center", justifyContent: "center", margin: "12px 0 6px" },
    dateSepText: { fontSize: 11, color: "#8a95a3", background: "#eaecf1", padding: "3px 13px", borderRadius: 20, fontWeight: 500 },
    row: { display: "flex", alignItems: "flex-end", gap: 7, marginBottom: 4 },
    miniAvatar: { width: 24, height: 24, borderRadius: "50%", flexShrink: 0, background: "linear-gradient(135deg,#6366f1,#8b5cf6)", color: "#fff", fontSize: 10, fontWeight: 700, display: "flex", alignItems: "center", justifyContent: "center" },
    bubble: { maxWidth: "72%", padding: "9px 12px", borderRadius: 16, wordBreak: "break-word", boxShadow: "0 1px 2px rgba(0,0,0,.06)" },
    bubbleMe: { background: "linear-gradient(135deg,#ff3e43,#ff6565)", color: "#fff", borderBottomRightRadius: 4 },
    bubbleThem: { background: "#fff", color: "#1f2937", borderBottomLeftRadius: 4, border: "1px solid #eef0f4" },
    msgText: { margin: 0, fontSize: 14, lineHeight: 1.5 },
    msgMeta: { display: "flex", alignItems: "center", justifyContent: "flex-end", gap: 2, marginTop: 4 },
    msgTime: { fontSize: 10, lineHeight: 1 },
    footer: { padding: "11px 14px", borderTop: "1px solid #f1f3f6", display: "flex", gap: 9, alignItems: "center", background: "#fff" },
    input: { flex: 1, padding: "10px 16px", border: "1.5px solid #eef0f4", borderRadius: 24, outline: "none", fontSize: 14, color: "#111827", background: "#f6f7fb", transition: "border-color .2s,box-shadow .2s,background .2s" },
    sendBtn: { width: 38, height: 38, borderRadius: "50%", background: "linear-gradient(135deg,#ff3e43,#ff6565)", border: "none", flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "0 2px 8px rgba(255,62,67,.3)", transition: "transform .15s" },
    newMsgBadge: {
        position: "absolute", bottom: 72, left: "50%", transform: "translateX(-50%)",
        background: "linear-gradient(135deg,#ff3e43,#ff6565)",
        color: "#fff", fontSize: 12, fontWeight: 600,
        padding: "7px 18px", borderRadius: 20,
        cursor: "pointer", zIndex: 10,
        boxShadow: "0 4px 16px rgba(255,62,67,.4)",
        whiteSpace: "nowrap",
        animation: "fadeIn .2s ease",
    },
};